(window.webpackJsonp=window.webpackJsonp||[]).push([[656],{634:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * // This is the CustomFunction\'s API interface.\\n * // You should not implement it, or speculate about its implementation\\n * function CustomFunction() {\\n *\\n *     <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{integer, integer}</span> </span>x, y\\n *     <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{integer}</span></span>\\n *     this.f = function(x, y) {\\n *         ...\\n *     };\\n *\\n * };\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{CustomFunction}</span> <span class=\\"hljs-variable\\">customfunction</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{integer}</span> <span class=\\"hljs-variable\\">z</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{integer[][]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findSolution = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">customfunction, z</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=<span class=\\"hljs-number\\">1000</span>;i++){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">1</span>;j&lt;=<span class=\\"hljs-number\\">1000</span>;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(customfunction.f(i,j)===z){\\n          res.push([i,j])\\n        }\\n      }\\n    }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"find-positive-integer-solution-for-a-given-equation","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u51fd\u6570\xa0\xa0<code>f(x, y)</code>\xa0\u548c\u4e00\u4e2a\u76ee\u6807\u7ed3\u679c\xa0<code>z</code>\uff0c\u51fd\u6570\u516c\u5f0f\u672a\u77e5\uff0c\u8bf7\u4f60\u8ba1\u7b97\u65b9\u7a0b\xa0<code>f(x,y) == z</code>\xa0\u6240\u6709\u53ef\u80fd\u7684\u6b63\u6574\u6570 <strong>\u6570\u5bf9</strong>\xa0<code>x</code> \u548c <code>y</code>\u3002\u6ee1\u8db3\u6761\u4ef6\u7684\u7ed3\u679c\u6570\u5bf9\u53ef\u4ee5\u6309\u4efb\u610f\u987a\u5e8f\u8fd4\u56de\u3002</p>\\n\\n<p>\u5c3d\u7ba1\u51fd\u6570\u7684\u5177\u4f53\u5f0f\u5b50\u672a\u77e5\uff0c\u4f46\u5b83\u662f\u5355\u8c03\u9012\u589e\u51fd\u6570\uff0c\u4e5f\u5c31\u662f\u8bf4\uff1a</p>\\n\\n<ul>\\n\\t<li><code>f(x, y) < f(x + 1, y)</code></li>\\n\\t<li><code>f(x, y) < f(x, y + 1)</code></li>\\n</ul>\\n\\n<p>\u51fd\u6570\u63a5\u53e3\u5b9a\u4e49\u5982\u4e0b\uff1a</p>\\n\\n<pre>\\ninterface CustomFunction {\\npublic:\\n  // Returns some positive integer f(x, y) for two positive integers x and y based on a formula.\\n  int f(int x, int y);\\n};</pre>\\n\\n<p>\u4f60\u7684\u89e3\u51b3\u65b9\u6848\u5c06\u6309\u5982\u4e0b\u89c4\u5219\u8fdb\u884c\u8bc4\u5224\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5224\u9898\u7a0b\u5e8f\u6709\u4e00\u4e2a\u7531 <code>CustomFunction</code> \u7684 <code>9</code> \u79cd\u5b9e\u73b0\u7ec4\u6210\u7684\u5217\u8868\uff0c\u4ee5\u53ca\u4e00\u79cd\u4e3a\u7279\u5b9a\u7684 <code>z</code> \u751f\u6210\u6240\u6709\u6709\u6548\u6570\u5bf9\u7684\u7b54\u6848\u7684\u65b9\u6cd5\u3002</li>\\n\\t<li>\u5224\u9898\u7a0b\u5e8f\u63a5\u53d7\u4e24\u4e2a\u8f93\u5165\uff1a<code>function_id</code>\uff08\u51b3\u5b9a\u4f7f\u7528\u54ea\u79cd\u5b9e\u73b0\u6d4b\u8bd5\u4f60\u7684\u4ee3\u7801\uff09\u4ee5\u53ca\u76ee\u6807\u7ed3\u679c <code>z</code> \u3002</li>\\n\\t<li>\u5224\u9898\u7a0b\u5e8f\u5c06\u4f1a\u8c03\u7528\u4f60\u5b9e\u73b0\u7684 <code>findSolution</code> \u5e76\u5c06\u4f60\u7684\u7ed3\u679c\u4e0e\u7b54\u6848\u8fdb\u884c\u6bd4\u8f83\u3002</li>\\n\\t<li>\u5982\u679c\u4f60\u7684\u7ed3\u679c\u4e0e\u7b54\u6848\u76f8\u7b26\uff0c\u90a3\u4e48\u89e3\u51b3\u65b9\u6848\u5c06\u88ab\u89c6\u4f5c\u6b63\u786e\u7b54\u6848\uff0c\u5373 <code>Accepted</code> \u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>function_id = 1, z = 5\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,4],[2,3],[3,2],[4,1]]\\n<strong>\u89e3\u91ca\uff1a</strong>function_id = 1 \u6697\u542b\u7684\u51fd\u6570\u5f0f\u5b50\u4e3a f(x, y) = x + y\\n\u4ee5\u4e0b x \u548c y \u6ee1\u8db3 f(x, y) \u7b49\u4e8e 5\uff1a\\nx=1, y=4 -> f(1, 4) = 1 + 4 = 5\\nx=2, y=3 -> f(2, 3) = 2 + 3 = 5\\nx=3, y=2 -> f(3, 2) = 3 + 2 = 5\\nx=4, y=1 -> f(4, 1) = 4 + 1 = 5\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>function_id = 2, z = 5\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,5],[5,1]]\\n<strong>\u89e3\u91ca\uff1a</strong>function_id = 2 \u6697\u542b\u7684\u51fd\u6570\u5f0f\u5b50\u4e3a f(x, y) = x * y\\n\u4ee5\u4e0b x \u548c y \u6ee1\u8db3 f(x, y) \u7b49\u4e8e 5\uff1a\\nx=1, y=5 -> f(1, 5) = 1 * 5 = 5\\nx=5, y=1 -> f(5, 1) = 5 * 1 = 5</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= function_id <= 9</code></li>\\n\\t<li><code>1 <= z <= 100</code></li>\\n\\t<li>\u9898\u76ee\u4fdd\u8bc1\xa0<code>f(x, y) == z</code>\xa0\u7684\u89e3\u5904\u4e8e\xa0<code>1 <= x, y <= 1000</code>\xa0\u7684\u8303\u56f4\u5185\u3002</li>\\n\\t<li>\u5728 <code>1 <= x, y <= 1000</code>\xa0\u7684\u524d\u63d0\u4e0b\uff0c\u9898\u76ee\u4fdd\u8bc1\xa0<code>f(x, y)</code>\xa0\u662f\u4e00\u4e2a\xa032 \u4f4d\u6709\u7b26\u53f7\u6574\u6570\u3002</li>\\n</ul>\\n","title":"1237. \u627e\u51fa\u7ed9\u5b9a\u65b9\u7a0b\u7684\u6b63\u6574\u6570\u89e3","relatedTags":["\u6570\u5b66","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1237"}')}}]);